<script>
import { client, config } from "@/lib/runtime.js";
import sideBar from "@/components/SideBar.vue";
import { ElMessage } from "element-plus";

export default {
  components: {
    sideBar,
  },
  data() {
    const displayConfig = config.getBaseConfig();
    const onPhone = window.innerWidth < 768;
    return {
      onPhone,
      client: client,
      beian: displayConfig?.beian || "",
    };
  },
  computed: {
    onPrivate() {
      return (
        this.$route.path.includes("/auth") ||
        this.$route.path.includes("/profile") ||
        this.$route.path.includes("/chat")
      );
    },
    isDashboardPage() {
      return this.$route.path === "/dashboard";
    },
  },
  created() {
    // 自动适配系统/本地缓存的暗黑模式状态
    this.updateTheme = () => {
      const savedTheme = localStorage.getItem("theme");
      const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
      const isDark = savedTheme === "dark" || (!savedTheme && prefersDark);
      
      if (isDark) {
        document.documentElement.setAttribute("data-theme", "dark");
        document.documentElement.classList.add("dark");
      } else {
        document.documentElement.removeAttribute("data-theme");
        document.documentElement.classList.remove("dark");
      }
    };
    
    this.updateTheme();
    
    // 监听系统主题偏好改变
    this.mediaQueryListener = window.matchMedia("(prefers-color-scheme: dark)");
    this.handleSystemThemeChange = (e) => {
      if (!localStorage.getItem("theme")) {
        if (e.matches) {
          document.documentElement.setAttribute("data-theme", "dark");
          document.documentElement.classList.add("dark");
        } else {
          document.documentElement.removeAttribute("data-theme");
          document.documentElement.classList.remove("dark");
        }
      }
    };
    this.mediaQueryListener.addEventListener("change", this.handleSystemThemeChange);

    const displayConfig = config.getBaseConfig();
    if (Object.keys(displayConfig).length > 0) {
      this.beian = displayConfig.beian;
      document.title = displayConfig.title;
    } else {
      config.setBaseConfigCallback((data) => {
        this.beian = data.beian;
        document.title = data.title;
      });
    }

    window.addEventListener("resize", this.handleResize);
    // 全局监听意外断连后重连成功，给用户一个 Toast
    client.on("connection_restored", () => {
      ElMessage.warning({
        message: "网络连接异常断开，已自动重连",
        duration: 3000,
      });
    });
  },
  beforeUnmount() {
    window.removeEventListener("resize", this.handleResize);
    if (this.mediaQueryListener && this.handleSystemThemeChange) {
      this.mediaQueryListener.removeEventListener("change", this.handleSystemThemeChange);
    }
  },
  methods: {
    handleResize() {
      this.onPhone = window.innerWidth < 768;
    },
  },
};
</script>
<template>
  <div v-if="isDashboardPage" class="app-full-viewport">
    <router-view></router-view>
  </div>
  <template v-else>
    <div id="mio-chat">
      <div v-if="onPhone" class="app-mobile">
        <router-view></router-view>
        <sideBar v-if="!onPrivate"></sideBar>
      </div>
      <div v-else class="app-desktop">
        <sideBar></sideBar>
        <router-view></router-view>
      </div>
    </div>
    <a
      v-if="beian"
      id="beian"
      href="https://beian.miit.gov.cn/"
      target="_blank"
      >{{ beian }}</a
    >
  </template>
</template>
